/*eslint-disable*/
import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";

export default function EmployeeNavbar({ employeeInfo, onUpdateProfile, onLogout }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [showJobOfferModal, setShowJobOfferModal] = useState(false);
  const [selectedJobOffer, setSelectedJobOffer] = useState(null);
  const [showResignConfirm, setShowResignConfirm] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
  const navigate = useNavigate();

  // ==================== إعدادات البروفيل ====================
  const [tempProfile, setTempProfile] = useState({
    name: employeeInfo?.name || "Ahmed Benali",
    location: employeeInfo?.location || "Alger, Algérie",
    phone: employeeInfo?.phone || "+213 5 55 55 55 55",
    bio: employeeInfo?.bio || "Passionné par la restauration depuis plus de 5 ans...",
    coverImage: employeeInfo?.coverImage || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    profileImage: employeeInfo?.profileImage || "https://randomuser.me/api/portraits/men/32.jpg"
  });

  // ==================== الروابط الاجتماعية (5 أيقونات) ====================
  const [socialLinks, setSocialLinks] = useState({
    facebook: "",
    instagram: "",
    twitter: "",
    linkedin: "",
    tiktok: ""
  });

  // ==================== استدعاءات العمل ====================
  const [jobOffers, setJobOffers] = useState([
    {
      id: 1,
      restaurantName: "Restaurant Andalous",
      location: "Alger, Algérie",
      description: "Nous recherchons un serveur expérimenté pour rejoindre notre équipe",
      logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
      image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      phone: "+213 5 55 55 55 55",
      email: "info@andalus-restaurant.dz",
      status: "pending" // pending, accepted, rejected
    },
    {
      id: 2,
      restaurantName: "Café Parisien",
      location: "Paris, France",
      description: "Barman recherché pour notre nouveau café",
      logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
      image: "https://images.unsplash.com/photo-1501339847302-ac426a4a7cbb",
      phone: "+33 6 12 34 56 78",
      email: "contact@cafeparisien.fr",
      status: "pending"
    }
  ]);

  const [currentJob, setCurrentJob] = useState(null); // العمل الحالي الذي يعمل فيه الموظف

  // ==================== دوال القبول والرفض ====================
  const acceptJobOffer = (offer) => {
    setJobOffers(jobOffers.map(job => 
      job.id === offer.id ? { ...job, status: "accepted" } : job
    ));
    setCurrentJob(offer);
    setShowJobOfferModal(false);
    alert(`✅ Vous avez accepté l'offre de ${offer.restaurantName}!`);
    
    // هنا يمكن إرسال إشعار للمدير أن موظفاً جديداً انضم
  };

  const rejectJobOffer = (offer) => {
    setJobOffers(jobOffers.filter(job => job.id !== offer.id));
    setShowJobOfferModal(false);
    alert(`❌ Vous avez refusé l'offre de ${offer.restaurantName}`);
  };

  // ==================== دوال الاستقالة ====================
  const resignFromJob = () => {
    setShowResignConfirm(false);
    setCurrentJob(null);
    alert("📝 Vous avez démissionné avec succès");
  };

  // ==================== دوال تسجيل الخروج ====================
  const handleLogout = () => {
    setShowLogoutConfirm(false);
    if (onLogout) {
      onLogout();
    } else {
      navigate("/");
    }
    alert("👋 Vous êtes déconnecté");
  };

  // ==================== دوال حفظ الإعدادات ====================
  const saveProfileSettings = () => {
    if (onUpdateProfile) {
      onUpdateProfile(tempProfile);
    }
    alert("✅ Profil mis à jour avec succès!");
    setSidebarOpen(false);
  };

  // ==================== دوال الروابط الاجتماعية ====================
  const updateSocialLink = (platform, url) => {
    setSocialLinks({ ...socialLinks, [platform]: url });
  };

  const saveSocialLinks = () => {
    alert("✅ Liens sociaux mis à jour!");
    setSidebarOpen(false);
  };

  // ==================== أيقونات التواصل الاجتماعي ====================
  const SocialIcons = () => (
    <div className="flex justify-center gap-4 mt-4">
      {socialLinks.facebook && (
        <a href={socialLinks.facebook} target="_blank" rel="noopener noreferrer" className="text-blue-500 hover:text-blue-400 transition-all duration-300 transform hover:scale-110">
          <i className="fab fa-facebook-f text-xl"></i>
        </a>
      )}
      {socialLinks.instagram && (
        <a href={socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="text-pink-500 hover:text-pink-400 transition-all duration-300 transform hover:scale-110">
          <i className="fab fa-instagram text-xl"></i>
        </a>
      )}
      {socialLinks.twitter && (
        <a href={socialLinks.twitter} target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 transition-all duration-300 transform hover:scale-110">
          <i className="fab fa-twitter text-xl"></i>
        </a>
      )}
      {socialLinks.linkedin && (
        <a href={socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="text-blue-700 hover:text-blue-600 transition-all duration-300 transform hover:scale-110">
          <i className="fab fa-linkedin-in text-xl"></i>
        </a>
      )}
      {socialLinks.tiktok && (
        <a href={socialLinks.tiktok} target="_blank" rel="noopener noreferrer" className="text-white hover:text-gray-300 transition-all duration-300 transform hover:scale-110">
          <i className="fab fa-tiktok text-xl"></i>
        </a>
      )}
    </div>
  );

  // ==================== ستايل النافبار والنافذة الجانبية ====================
  const styles = `
    @keyframes slideIn {
      from { transform: translateX(-100%); }
      to { transform: translateX(0); }
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .sidebar-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.7);
      z-index: 1000;
      animation: fadeIn 0.3s ease;
    }
    
    .sidebar {
      position: fixed;
      top: 0;
      left: 0;
      width: 85%;
      max-width: 400px;
      height: 100vh;
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      z-index: 1001;
      padding: 20px;
      overflow-y: auto;
      animation: slideIn 0.3s ease;
      border-right: 2px solid #22c55e;
      box-shadow: 5px 0 30px rgba(0,0,0,0.5);
    }
    
    .sidebar::-webkit-scrollbar {
      width: 6px;
    }
    
    .sidebar::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
    }
    
    .sidebar::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    .sidebar-section {
      margin-bottom: 25px;
      padding-bottom: 20px;
      border-bottom: 1px solid rgba(255,255,255,0.1);
    }
    
    .sidebar-title {
      color: #22c55e;
      font-size: 1.1rem;
      font-weight: bold;
      margin-bottom: 15px;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    
    .sidebar-input {
      width: 100%;
      padding: 10px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
      margin-bottom: 10px;
    }
    
    .sidebar-input:focus {
      outline: none;
      border-color: #22c55e;
    }
    
    .sidebar-label {
      color: rgba(255,255,255,0.7);
      font-size: 0.8rem;
      margin-bottom: 5px;
      display: block;
    }
    
    .btn-sidebar {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      width: 100%;
      margin-top: 10px;
      transition: all 0.2s;
    }
    
    .btn-sidebar:hover {
      transform: scale(1.02);
    }
    
    .btn-danger-sidebar {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
    }
    
    .current-job-card {
      background: rgba(34,197,94,0.2);
      border: 1px solid #22c55e;
      border-radius: 15px;
      padding: 12px;
      margin-bottom: 15px;
    }
    
    .job-offer-card {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 12px;
      margin-bottom: 12px;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .job-offer-card:hover {
      background: rgba(255,255,255,0.15);
      transform: translateX(5px);
    }
    
    .modal-overlay-custom {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.95);
      backdrop-filter: blur(10px);
      z-index: 1100;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .modal-content-custom {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 25px;
      max-width: 500px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      animation: fadeIn 0.3s ease;
    }
    
    .confirm-buttons {
      display: flex;
      gap: 15px;
      justify-content: center;
      margin-top: 20px;
    }
    
    .navbar-custom-employee {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      box-shadow: 0 4px 20px rgba(34,197,94,0.2);
    }
    
    .menu-btn {
      background: rgba(34,197,94,0.2);
      border: 1px solid #22c55e;
      border-radius: 50%;
      width: 40px;
      height: 40px;
      display: flex;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .menu-btn:hover {
      background: #22c55e;
      transform: scale(1.05);
    }
    
    .social-icon-placeholder {
      width: 36px;
      height: 36px;
      background: rgba(255,255,255,0.1);
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      color: rgba(255,255,255,0.4);
      font-size: 1rem;
      transition: all 0.3s;
    }
    
    .social-icon-placeholder.active {
      background: rgba(34,197,94,0.3);
      color: #22c55e;
      cursor: pointer;
    }
    
    .social-icon-placeholder.active:hover {
      transform: scale(1.1);
      background: #22c55e;
      color: white;
    }
  `;

  // ==================== عرض النافبار ====================
  return (
    <>
      <style>{styles}</style>
      
      <nav className="top-0 fixed z-50 w-full flex flex-wrap items-center justify-between px-2 py-3 navbar-custom-employee shadow-lg">
        <div className="container px-4 mx-auto flex flex-wrap items-center justify-between">
          <div className="w-full relative flex justify-between lg:w-auto lg:static lg:block lg:justify-start">
            {/* أيقونة القائمة (ثلاث خطوط) */}
            <div className="menu-btn" onClick={() => setSidebarOpen(true)}>
              <i className="fas fa-bars text-white text-xl"></i>
            </div>
            
            <Link
              to="/employee-profile"
              className="text-green-400 text-sm font-bold leading-relaxed inline-block mr-4 py-2 whitespace-nowrap uppercase ml-3"
              style={{
                textShadow: "0 0 10px rgba(34,197,94,0.5)",
                letterSpacing: "1px"
              }}
            >
              👨‍🍳 Espace Employé
            </Link>
          </div>
          
          <div className="flex items-center gap-3">
            {/* أيقونة الإشعارات */}
            <div className="relative">
              <i className="fas fa-bell text-white text-lg cursor-pointer hover:text-green-400 transition"></i>
              {jobOffers.filter(j => j.status === "pending").length > 0 && (
                <span className="absolute -top-2 -right-2 bg-red-500 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center">
                  {jobOffers.filter(j => j.status === "pending").length}
                </span>
              )}
            </div>
            
            {/* أيقونة الرسائل */}
            <i className="fas fa-envelope text-white text-lg cursor-pointer hover:text-green-400 transition"></i>
          </div>
        </div>
      </nav>
      
      {/* ========== النافذة الجانبية (Sidebar) ========== */}
      {sidebarOpen && (
        <>
          <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)}></div>
          <div className="sidebar">
            <button 
              onClick={() => setSidebarOpen(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}
            >
              ✕
            </button>
            
            {/* صورة البروفيل المصغرة */}
            <div className="text-center mb-5">
              <img 
                src={tempProfile.profileImage} 
                alt="profile" 
                style={{ width: '80px', height: '80px', borderRadius: '50%', margin: '0 auto', border: '2px solid #22c55e' }}
              />
              <h4 className="text-white mt-2">{tempProfile.name}</h4>
            </div>
            
            {/* ====== قسم الإعدادات ====== */}
            <div className="sidebar-section">
              <div className="sidebar-title">
                <i className="fas fa-sliders-h"></i> Paramètres du profil
              </div>
              
              <label className="sidebar-label">🖼️ Image de couverture (URL)</label>
              <input 
                type="text" 
                className="sidebar-input" 
                value={tempProfile.coverImage}
                onChange={(e) => setTempProfile({...tempProfile, coverImage: e.target.value})}
                placeholder="https://example.com/cover.jpg"
              />
              
              <label className="sidebar-label">👤 Image de profil (URL)</label>
              <input 
                type="text" 
                className="sidebar-input" 
                value={tempProfile.profileImage}
                onChange={(e) => setTempProfile({...tempProfile, profileImage: e.target.value})}
                placeholder="https://example.com/profile.jpg"
              />
              
              <label className="sidebar-label">📛 Nom complet</label>
              <input 
                type="text" 
                className="sidebar-input" 
                value={tempProfile.name}
                onChange={(e) => setTempProfile({...tempProfile, name: e.target.value})}
              />
              
              <label className="sidebar-label">📍 Ville</label>
              <input 
                type="text" 
                className="sidebar-input" 
                value={tempProfile.location}
                onChange={(e) => setTempProfile({...tempProfile, location: e.target.value})}
              />
              
              <label className="sidebar-label">📞 Téléphone</label>
              <input 
                type="tel" 
                className="sidebar-input" 
                value={tempProfile.phone}
                onChange={(e) => setTempProfile({...tempProfile, phone: e.target.value})}
              />
              
              <label className="sidebar-label">📝 Bio</label>
              <textarea 
                className="sidebar-input" 
                rows="3"
                value={tempProfile.bio}
                onChange={(e) => setTempProfile({...tempProfile, bio: e.target.value})}
                placeholder="Parlez de vous..."
              ></textarea>
              
              <button className="btn-sidebar" onClick={saveProfileSettings}>
                💾 Enregistrer les modifications
              </button>
            </div>
            
            {/* ====== قسم الروابط الاجتماعية ====== */}
            <div className="sidebar-section">
              <div className="sidebar-title">
                <i className="fas fa-share-alt"></i> Liens sociaux
              </div>
              
              <label className="sidebar-label">📘 Facebook</label>
              <input type="text" className="sidebar-input" placeholder="https://facebook.com/..." value={socialLinks.facebook} onChange={(e) => updateSocialLink('facebook', e.target.value)} />
              
              <label className="sidebar-label">📷 Instagram</label>
              <input type="text" className="sidebar-input" placeholder="https://instagram.com/..." value={socialLinks.instagram} onChange={(e) => updateSocialLink('instagram', e.target.value)} />
              
              <label className="sidebar-label">🐦 Twitter</label>
              <input type="text" className="sidebar-input" placeholder="https://twitter.com/..." value={socialLinks.twitter} onChange={(e) => updateSocialLink('twitter', e.target.value)} />
              
              <label className="sidebar-label">🔗 LinkedIn</label>
              <input type="text" className="sidebar-input" placeholder="https://linkedin.com/..." value={socialLinks.linkedin} onChange={(e) => updateSocialLink('linkedin', e.target.value)} />
              
              <label className="sidebar-label">🎵 TikTok</label>
              <input type="text" className="sidebar-input" placeholder="https://tiktok.com/..." value={socialLinks.tiktok} onChange={(e) => updateSocialLink('tiktok', e.target.value)} />
              
              <button className="btn-sidebar" onClick={saveSocialLinks}>
                💾 Enregistrer les liens
              </button>
            </div>
            
            {/* ====== قسم العمل الحالي والاستقالة ====== */}
            {currentJob && (
              <div className="sidebar-section">
                <div className="sidebar-title">
                  <i className="fas fa-briefcase"></i> Emploi actuel
                </div>
                <div className="current-job-card">
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    <img src={currentJob.logo} alt="logo" style={{ width: '40px', height: '40px', borderRadius: '10px' }} />
                    <div>
                      <h4 style={{ color: '#22c55e', margin: 0 }}>{currentJob.restaurantName}</h4>
                      <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem', margin: 0 }}>{currentJob.location}</p>
                    </div>
                  </div>
                </div>
                <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowResignConfirm(true)}>
                  📤 Démissionner
                </button>
              </div>
            )}
            
            {/* ====== قسم استدعاءات العمل ====== */}
            <div className="sidebar-section">
              <div className="sidebar-title">
                <i className="fas fa-bell"></i> Offres d'emploi reçues
                {jobOffers.filter(j => j.status === "pending").length > 0 && (
                  <span className="bg-red-500 text-white text-xs rounded-full px-2 py-1 ml-2">
                    {jobOffers.filter(j => j.status === "pending").length} nouvelle(s)
                  </span>
                )}
              </div>
              
              {jobOffers.filter(j => j.status === "pending").length === 0 ? (
                <p className="text-gray-400 text-sm text-center">Aucune offre pour le moment</p>
              ) : (
                jobOffers.filter(j => j.status === "pending").map(offer => (
                  <div key={offer.id} className="job-offer-card" onClick={() => {
                    setSelectedJobOffer(offer);
                    setShowJobOfferModal(true);
                  }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                      <img src={offer.logo} alt="logo" style={{ width: '35px', height: '35px', borderRadius: '8px' }} />
                      <div>
                        <h4 style={{ color: 'white', margin: 0, fontSize: '0.9rem' }}>{offer.restaurantName}</h4>
                        <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.7rem', margin: 0 }}>{offer.location}</p>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
            
            {/* ====== زر تسجيل الخروج ====== */}
            <div className="sidebar-section">
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(true)}>
                🚪 Déconnexion
              </button>
            </div>
          </div>
        </>
      )}
      
      {/* ========== مودال عرض كرت المطعم عند استدعاء العمل ========== */}
      {showJobOfferModal && selectedJobOffer && (
        <div className="modal-overlay-custom" onClick={() => setShowJobOfferModal(false)}>
          <div className="modal-content-custom" onClick={(e) => e.stopPropagation()}>
            <button 
              onClick={() => setShowJobOfferModal(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '20px', cursor: 'pointer' }}
            >
              ✕
            </button>
            
            <div className="text-center">
              <img src={selectedJobOffer.logo} alt="logo" style={{ width: '70px', height: '70px', borderRadius: '50%', marginBottom: '10px' }} />
              <h3 style={{ color: '#22c55e', marginBottom: '5px' }}>{selectedJobOffer.restaurantName}</h3>
              <p style={{ color: 'rgba(255,255,255,0.7)' }}>📍 {selectedJobOffer.location}</p>
            </div>
            
            <img src={selectedJobOffer.image} alt="restaurant" style={{ width: '100%', height: '150px', objectFit: 'cover', borderRadius: '15px', margin: '15px 0' }} />
            
            <p style={{ color: 'rgba(255,255,255,0.8)', marginBottom: '15px' }}>{selectedJobOffer.description}</p>
            
            <div style={{ marginBottom: '15px' }}>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>📞 {selectedJobOffer.phone}</p>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>✉️ {selectedJobOffer.email}</p>
            </div>
            
            <div className="confirm-buttons">
              <button 
                className="btn-sidebar" 
                style={{ background: '#22c55e' }}
                onClick={() => acceptJobOffer(selectedJobOffer)}
              >
                ✅ Accepter
              </button>
              <button 
                className="btn-sidebar btn-danger-sidebar" 
                onClick={() => rejectJobOffer(selectedJobOffer)}
              >
                ❌ Refuser
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* ========== مودال تأكيد الاستقالة ========== */}
      {showResignConfirm && (
        <div className="modal-overlay-custom" onClick={() => setShowResignConfirm(false)}>
          <div className="modal-content-custom" style={{ maxWidth: '350px' }} onClick={(e) => e.stopPropagation()}>
            <h3 style={{ color: 'white', textAlign: 'center', marginBottom: '15px' }}>⚠️ Démission</h3>
            <p style={{ color: 'rgba(255,255,255,0.8)', textAlign: 'center', marginBottom: '20px' }}>
              Êtes-vous sûr de vouloir démissionner ?
            </p>
            <div className="confirm-buttons">
              <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={resignFromJob}>
                Oui
              </button>
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowResignConfirm(false)}>
                Non
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* ========== مودال تأكيد تسجيل الخروج ========== */}
      {showLogoutConfirm && (
        <div className="modal-overlay-custom" onClick={() => setShowLogoutConfirm(false)}>
          <div className="modal-content-custom" style={{ maxWidth: '350px' }} onClick={(e) => e.stopPropagation()}>
            <h3 style={{ color: 'white', textAlign: 'center', marginBottom: '15px' }}>🚪 Déconnexion</h3>
            <p style={{ color: 'rgba(255,255,255,0.8)', textAlign: 'center', marginBottom: '20px' }}>
              Êtes-vous sûr de vouloir vous déconnecter ?
            </p>
            <div className="confirm-buttons">
              <button className="btn-sidebar" style={{ background: '#22c55e' }} onClick={handleLogout}>
                Oui
              </button>
              <button className="btn-sidebar btn-danger-sidebar" onClick={() => setShowLogoutConfirm(false)}>
                Non
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* ========== أيقونات التواصل الاجتماعي في الفوتر ========== */}
      <div style={{ position: 'fixed', bottom: '20px', left: 0, right: 0, zIndex: 50 }}>
        <SocialIcons />
      </div>
    </>
  );
}
